import axios from "axios";

async function createHDJob(url) {
  const api = `https://api-faa.my.id/faa/hdvid?url=${encodeURIComponent(url)}`;
  const res = await axios.get(api);

  if (res.data?.status && res.data?.job_id) {
    return res.data.job_id;
  }

  return null;
}

async function checkHDJob(jobId) {
  const api = `https://api-faa.my.id/faa/result?id=${jobId}`;
  const res = await axios.get(api);
  return res.data;
}

async function handle(sock, messageInfo) {
  const { remoteJid, message, prefix, command, content } = messageInfo;

  try {
    const url = content.trim();

    if (!url) {
      return await sock.sendMessage(
        remoteJid,
        {
          text:
            `_⚠️ Format Penggunaan:_\n\n` +
            `🎥 Contoh:\n*${prefix + command} https://h.uguu.se/video.mp4*`
        },
        { quoted: message }
      );
    }

    await sock.sendMessage(
      remoteJid,
      {
        react: {
          text: "⏳",
          key: message.key
        }
      }
    );

    const jobId = await createHDJob(url);

    if (!jobId) {
      return await sock.sendMessage(
        remoteJid,
        {
          text: "❌ Gagal membuat job HD Video"
        },
        { quoted: message }
      );
    }

    console.log(`[HDVID] Job dibuat -> ${jobId}`);

    const checker = setInterval(async () => {
      try {
        const result = await checkHDJob(jobId);

        console.log(`[HDVID] ${jobId} -> ${result.state}`);

        if (result?.state === "processing") {
          return;
        }

        clearInterval(checker);

        if (result?.state !== "done") {
          return console.log(`[HDVID] ${jobId} gagal diproses`);
        }

        const output = result.result;

        await sock.sendMessage(
          remoteJid,
          {
            video: {
              url: output.download_url
            },
            mimetype: "video/mp4",
            caption:
              `✅ *HD Video Selesai*\n\n` +
              `🎥 Format: ${output.format}\n` +
              `✨ Quality: ${output.quality}`
          },
          { quoted: message }
        );

      } catch (err) {
        console.log(`[HDVID ERROR] ${jobId}`, err.message);
      }
    }, 30000);

  } catch (error) {
    await sock.sendMessage(
      remoteJid,
      {
        text:
          `❌ Maaf, terjadi kesalahan saat memproses video.\n\n` +
          `${error.message}`
      },
      { quoted: message }
    );
  }
}

export default {
  handle,
  Commands: ["hdvid", "hdvideo"],
  OnlyPremium: false,
  OnlyOwner: false,
  limitDeduction: 1
};
